const AWS = require('aws-sdk');

exports.handler = async (event) => {
  const s3 = new AWS.S3({ region: 'your-region' });

  event.Records.forEach((record) => {
    if (record.eventName === 'ObjectCreated:Put') {
      const bucket = record.s3.bucket.name;
      const key = record.s3.object.key;

      try {
        const fileContent = s3.getObject({
          Bucket: bucket,
          Key: key
        }).promise();

        // Process the file content here (e.g., OCR, text extraction)
        const processedContent = processFile(fileContent);

        // Save results to another S3 location
        const outputBucket = 'output-bucket';
        const outputFile = `${key.split('.')[0]}_processed.${key.split('.').pop()}`;
        s3.putObject({
          Bucket: outputBucket,
          Key: outputFile,
          Body: processedContent
        }).promise();
      } catch (error) {
        console.error(error);
      }
    }
  });

  return { statusCode: 200 };
};

function processFile(fileContent) {
  // Implement your file processing logic here
  // For example, you can use a library like tesseract.js for OCR
  const processedContent = fileContent.toString();
  return processedContent;
}